  ('elementary-6f0ba476-moex-00965', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-4bd2866a', 'sub-elementary-6f0ba476-04', NULL, 'single_choice', '關於雷姆斯法則（Ramseyrule）與反需求彈性法則，下列何者錯誤？', '["雷姆斯法則指最適租稅的制訂必須滿足所有財貨被課稅後，受補償需求量的變動幅度均一樣之條件", "依據反需求彈性法則，政府應該對奢侈品課徵較高的稅率，而對民生必需品則課徵較低的稅率", "依據反需求彈性法則，政府應對受補償需求彈性大的財貨課徵較低的稅率", "為達到次佳（secondbest）的目標，對財貨稅率的訂定應依循雷姆斯法則"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "823acbf432c6", "answer_pdf_sha1": "254e7c083307", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "財政學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00966', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-4bd2866a', 'sub-elementary-6f0ba476-04', NULL, 'single_choice', '橫軸為稅率，縱軸為稅收時，拉弗曲線（Laffercurve）產生負斜率的原因為：', '["稅率增加導致稅基增加，且稅基增加的效果大於稅率增加的效果", "稅率減少導致稅基增加，且稅基增加的效果低於稅率減少的效果", "稅率增加導致稅基減少，且稅基減少的效果低於稅率增加的效果", "稅率增加導致稅基減少，且稅基減少的效果大於稅率增加的效果"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "823acbf432c6", "answer_pdf_sha1": "254e7c083307", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "財政學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
