  ('elementary-6f0ba476-moex-00969', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-110-4bd2866a', 'sub-elementary-6f0ba476-04', NULL, 'single_choice', '租稅歸宿的部分均衡分析與一般均衡分析之間的差別何在？', '["前者僅分析所得重分配效果，後者則分析效率效果", "前者僅進行短期分析，後者則考慮長期影響", "前者僅考慮價格的調整，後者則考慮價格與數量兩者的影響", "前者僅考慮被課稅市場的影響，後者考慮課稅對所有相關市場之影響"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:43+00:00", "source_pdf_sha1": "823acbf432c6", "answer_pdf_sha1": "254e7c083307", "source_family": "moex-gov-tw", "moex": {"exam_code": "110010", "c": "507", "s": "0503", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "財政學大意", "year": "110", "exam_name": "110年公務人員初等考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
